#!/usr/bin/env python3
"""
Supply Chain Quality Offender Analysis v2

Properly simulates the supply chain and identifies quality offenders.
"""

import csv
import json
import os
import re
from collections import defaultdict
from glob import glob


def parse_order_file(filepath):
    """Parse order file and return list of (product_id, qty)."""
    content = open(filepath).read()
    products = []

    if filepath.endswith('.json'):
        try:
            import json as j
            data = j.loads(content)
            for item in data.get('items', []):
                pid = item.get('prod_id', '')
                qty = int(item.get('qty', 0))
                if pid:
                    products.append((pid, qty))
            return products
        except:
            pass

    if filepath.endswith('.csv'):
        for line in content.strip().split('\n')[1:]:
            parts = line.strip().split(';')
            if len(parts) >= 2:
                products.append((parts[0].strip(), int(parts[1].strip())))
        return products

    if 'ORDER_PRODUCT' in content:
        for line in content.strip().split('\n'):
            m = re.search(r'ORDER_PRODUCT:\s*(\S+)', line)
            m2 = re.search(r'ORDER_QTY:\s*(\d+)', line)
            if m and m2:
                products.append((m.group(1), int(m2.group(1))))
        return products

    for line in content.strip().split('\n'):
        m = re.search(r'(\d+)\s+units of product\s+(P_\d+)', line)
        if m:
            products.append((m.group(2), int(m.group(1))))

    return products


def load_all_orders():
    orders = {}
    for fp in glob('/app/raw_orders/day_*'):
        fname = os.path.basename(fp)
        parts = fname.split('_')
        day = int(parts[1])
        store = parts[2] + '_' + parts[3]
        prods = parse_order_file(fp)
        if prods:
            orders[(day, store)] = dict(prods)
    return orders


def parse_supplier_file(filepath):
    content = open(filepath).read()
    products = []

    if filepath.endswith('.json'):
        try:
            import json as j
            data = j.loads(content)
            for item in data.get('items', []):
                pid = item.get('prod_id', '')
                qty = int(item.get('delivered_qty', 0))
                if pid:
                    products.append((pid, qty))
            return products
        except:
            pass

    if filepath.endswith('.csv'):
        for line in content.strip().split('\n')[1:]:
            parts = line.strip().split(';')
            if len(parts) >= 2:
                products.append((parts[0].strip(), int(parts[1].strip())))
        return products

    if 'PRODUCT' in content and 'DELIVERED_QTY' in content and 'SUPPLIER' not in content:
        for line in content.strip().split('\n'):
            m = re.search(r'PRODUCT:\s*(\S+)', line)
            m2 = re.search(r'DELIVERED_QTY:\s*(\d+)', line)
            if m and m2:
                products.append((m.group(1), int(m2.group(1))))
        return products

    for line in content.strip().split('\n'):
        m = re.search(r'delivered\s+(\d+)\s+units of product\s+(P_\d+)', line)
        if m:
            products.append((m.group(2), int(m.group(1))))

    return products


def load_supplier_receipts():
    deliveries = {}
    for fp in glob('/app/raw_supplier_receipts/day_*'):
        fname = os.path.basename(fp)
        parts = fname.split('_')
        day = int(parts[1])
        producer = parts[2] + '_' + parts[3]
        prods = parse_supplier_file(fp)
        if prods:
            deliveries[(day, producer)] = dict(prods)
    return deliveries


def load_wholesaler_receipts():
    """Returns dict: (day, producer) -> sequence_no"""
    ws_receipts = {}
    for fp in glob('/app/raw_wholesaler_receipts/day_*.txt'):
        fname = os.path.basename(fp)
        parts = fname.split('_')
        day = int(parts[1])
        producer = parts[2] + '_' + parts[3]
        content = open(fp).read()
        m = re.search(r'DAILY_SEQUENCE_NO:\s*(\d+)', content)
        if m:
            ws_receipts[(day, producer)] = int(m.group(1))
    return ws_receipts


def load_store_receipts():
    """Returns dict: (day, store) -> (sequence_no, total_units)"""
    st_receipts = {}
    for fp in glob('/app/raw_wholesaler_store_receipts/day_*.txt'):
        fname = os.path.basename(fp)
        parts = fname.split('_')
        day = int(parts[1])
        store = parts[2] + '_' + parts[3]
        content = open(fp).read()
        m1 = re.search(r'DAILY_SEQUENCE_NO:\s*(\d+)', content)
        m2 = re.search(r'TOTAL_DELIVERED_UNITS:\s*(\d+)', content)
        if m1 and m2:
            st_receipts[(day, store)] = (int(m1.group(1)), int(m2.group(1)))
    return st_receipts


def load_sales_log():
    """Returns aggregated sales: (day, store, product) -> (demand, sold, lost)"""
    sales = {}
    with open('/app/sales_log.csv') as f:
        reader = csv.DictReader(f)
        for row in reader:
            key = (int(row['Day']), row['Store_ID'], row['Product_ID'])
            d, s, l = sales.get(key, (0, 0, 0))
            sales[key] = (d + int(row['Reported_Demand']),
                          s + int(row['Sold_Quantity']),
                          l + int(row['Lost_Sales']))
    return sales


def load_raw_sales():
    """Returns all rows grouped by key"""
    sales = defaultdict(list)
    with open('/app/sales_log.csv') as f:
        reader = csv.DictReader(f)
        for row in reader:
            key = (int(row['Day']), row['Store_ID'], row['Product_ID'])
            sales[key].append({
                'demand': int(row['Reported_Demand']),
                'sold': int(row['Sold_Quantity']),
                'lost': int(row['Lost_Sales'])
            })
    return sales


def main():
    print("Loading data...")

    orders = load_all_orders()
    print(f"  Orders: {len(orders)} entries")

    supplier_deliveries = load_supplier_receipts()
    print(f"  Supplier deliveries: {len(supplier_deliveries)} entries")

    ws_receipts = load_wholesaler_receipts()
    print(f"  Wholesaler receipts: {len(ws_receipts)} entries")

    st_receipts = load_store_receipts()
    print(f"  Store receipts: {len(st_receipts)} entries")

    sales_agg = load_sales_log()
    print(f"  Sales aggregated: {len(sales_agg)} entries")

    raw_sales = load_raw_sales()

    # ------------------------------------------------------------
    # Group wholesaler receipts by day with sorted sequence numbers
    # ------------------------------------------------------------
    ws_by_day = defaultdict(list)
    for (day, producer), seq in ws_receipts.items():
        ws_by_day[day].append((seq, producer))
    for day in ws_by_day:
        ws_by_day[day].sort()

    # ------------------------------------------------------------
    # Group store receipts by day with sorted sequence numbers
    # ------------------------------------------------------------
    st_by_day = defaultdict(list)
    for (day, store), (seq, total) in st_receipts.items():
        st_by_day[day].append((seq, store, total))
    for day in st_by_day:
        st_by_day[day].sort()

    # ------------------------------------------------------------
    # SIMULATION: Day by day
    # ------------------------------------------------------------
    # Wholesaler inventory: product -> list of [producer, source_day, qty]
    wh_inv = defaultdict(list)

    # Store inventory: store -> product -> list of [producer, source_day, qty]
    store_inv = defaultdict(lambda: defaultdict(list))

    # Track store intake: (store, product, producer, source_day) -> qty received
    store_intake = defaultdict(int)

    max_day = max(max(ws_by_day.keys()), max(st_by_day.keys()))
    max_day = min(max_day, 365)  # sales only goes to 365

    for day in range(1, max_day + 1):
        # 1. Accept supplier deliveries in sequence order
        if day in ws_by_day:
            for seq, producer in ws_by_day[day]:
                key = (day, producer)
                if key in supplier_deliveries:
                    for prod, qty in supplier_deliveries[key].items():
                        wh_inv[prod].append([producer, day, qty])

        # 2. Fulfill store orders in sequence order
        if day in st_by_day and day in orders:
            # Get store orders for this day
            day_orders = {}
            for (d, store), order in orders.items():
                if d == day:
                    day_orders[store] = order

            for seq, store, total_units in st_by_day[day]:
                if store not in day_orders:
                    continue

                store_order = day_orders[store]
                total_ordered = sum(store_order.values())

                if total_ordered == 0:
                    continue

                # Determine fulfillment: proportional allocation
                # Step 1: For each product in the order, determine how much we can allocate
                alloc = {}

                for prod, ordered_qty in store_order.items():
                    available = sum(item[2] for item in wh_inv.get(prod, []))
                    if available > 0:
                        alloc[prod] = min(ordered_qty, available)

                total_alloc = sum(alloc.values())

                if total_alloc == 0:
                    continue

                # Scale allocation to match total_units if needed
                if total_alloc > total_units:
                    scale = total_units / total_alloc
                    for prod in alloc:
                        alloc[prod] = int(alloc[prod] * scale)
                    # Redistribute rounding
                    diff = total_units - sum(alloc.values())
                    if diff > 0:
                        for prod in sorted(alloc.keys()):  # deterministic
                            if diff <= 0:
                                break
                            add = min(diff, alloc[prod])
                            alloc[prod] += add
                            diff -= add

                # Actually allocate from wholesaler inventory (FIFO)
                for prod, alloc_qty in alloc.items():
                    remaining = alloc_qty
                    new_inv = []
                    for item in wh_inv.get(prod, []):
                        if remaining <= 0:
                            new_inv.append(item)
                        else:
                            producer, src_day, avail = item
                            take = min(avail, remaining)
                            if take > 0:
                                key = (store, prod, producer, src_day)
                                store_intake[key] += take
                                # Add to store inventory
                                store_inv[store][prod].append([producer, src_day, take])
                                remaining -= take
                            if avail - take > 0:
                                new_inv.append([producer, src_day, avail - take])
                    wh_inv[prod] = new_inv

    print(f"Simulation complete. Store intake entries: {len(store_intake)}")

    # ------------------------------------------------------------
    # Now analyze sales with inventory to detect quality issues
    # ------------------------------------------------------------
    # Copy store_inv for consumption tracking
    sim_inv = defaultdict(lambda: defaultdict(list))
    for store in store_inv:
        for prod in store_inv[store]:
            for item in store_inv[store][prod]:
                sim_inv[store][prod].append(item[:])

    confirmed = defaultdict(set)

    # Also track: after a quality rejection, consumers recover
    # recovery_state[store][product] = days_remaining_in_recovery or (state, days_left)
    # For tracking demand effects

    for day in range(1, 366):
        # Process sales for this day
        for store_idx in range(1, 11):
            store_id = f'S_{store_idx}'
            for prod_idx in range(1, 31):
                prod_id = f'P_{prod_idx}'
                key = (day, store_id, prod_id)

                if key not in sales_agg:
                    continue

                total_demand, total_sold, total_lost = sales_agg[key]

                # How much inventory does this store have for this product?
                inv_list = sim_inv.get(store_id, {}).get(prod_id, [])
                total_inv = sum(item[2] for item in inv_list)

                if total_lost > 0 and total_inv > 0:
                    # Lost sales with inventory available = quality rejection!
                    # The batch at the front of FIFO is the offender
                    if inv_list and inv_list[0][2] > 0:
                        producer = inv_list[0][0]
                        confirmed[prod_id].add(producer)

                # Consume inventory based on sold
                remaining = total_sold
                new_inv = []
                for item in inv_list:
                    if remaining <= 0:
                        new_inv.append(item)
                    else:
                        producer, src_day, avail = item
                        take = min(avail, remaining)
                        remaining -= take
                        if avail - take > 0:
                            new_inv.append([producer, src_day, avail - take])
                sim_inv[store_id][prod_id] = new_inv

    # Build result
    result = {}
    for i in range(1, 31):
        p = f'P_{i}'
        if p in confirmed:
            result[p] = sorted(confirmed[p], key=lambda x: int(x.split('_')[1]))
        else:
            result[p] = []

    print("\nConfirmed quality offenders:")
    for p, producers in result.items():
        print(f"  {p}: {producers}")

    with open('/app/answer.json', 'w') as f:
        json.dump(result, f, indent=2)

    print("\nWritten to /app/answer.json")


if __name__ == '__main__':
    main()

#!/usr/bin/env python3
"""
Supply Chain Quality Offender Analysis v3
"""

import csv
import json
import os
import re
from collections import defaultdict
from glob import glob

FN_PATTERN = re.compile(r'day_(\d+)_(S_\d+)')
SUP_PATTERN = re.compile(r'day_(\d+)_(PR_\d+)')
RECEIPT_PATTERN = re.compile(r'DAY:\s*(\d+)')


def parse_order_file(filepath):
    content = open(filepath).read()
    products = []

    if filepath.endswith('.json'):
        try:
            import json as j
            data = j.loads(content)
            for item in data.get('items', []):
                pid = item.get('prod_id', '')
                qty = int(item.get('qty', 0))
                if pid:
                    products.append((pid, qty))
            return products
        except:
            pass

    if filepath.endswith('.csv'):
        for line in content.strip().split('\n')[1:]:
            parts = line.strip().split(';')
            if len(parts) >= 2:
                products.append((parts[0].strip(), int(parts[1].strip())))
        return products

    if 'ORDER_PRODUCT' in content:
        for line in content.strip().split('\n'):
            m = re.search(r'ORDER_PRODUCT:\s*(\S+)', line)
            m2 = re.search(r'ORDER_QTY:\s*(\d+)', line)
            if m and m2:
                products.append((m.group(1), int(m2.group(1))))
        return products

    for line in content.strip().split('\n'):
        m = re.search(r'(\d+)\s+units of product\s+(P_\d+)', line)
        if m:
            products.append((m.group(2), int(m.group(1))))

    return products


def parse_supplier_file(filepath):
    content = open(filepath).read()
    products = []

    if filepath.endswith('.json'):
        try:
            import json as j
            data = j.loads(content)
            for item in data.get('items', []):
                pid = item.get('prod_id', '')
                qty = int(item.get('delivered_qty', 0))
                if pid:
                    products.append((pid, qty))
            return products
        except:
            pass

    if filepath.endswith('.csv'):
        for line in content.strip().split('\n')[1:]:
            parts = line.strip().split(';')
            if len(parts) >= 2:
                products.append((parts[0].strip(), int(parts[1].strip())))
        return products

    if 'PRODUCT' in content and 'DELIVERED_QTY' in content:
        for line in content.strip().split('\n'):
            m = re.search(r'PRODUCT:\s*(\S+)', line)
            m2 = re.search(r'DELIVERED_QTY:\s*(\d+)', line)
            if m and m2:
                products.append((m.group(1), int(m2.group(1))))
        return products

    for line in content.strip().split('\n'):
        m = re.search(r'delivered\s+(\d+)\s+units of product\s+(P_\d+)', line)
        if m:
            products.append((m.group(2), int(m.group(1))))

    return products


def main():
    print("Loading orders...")
    orders = {}
    for fp in glob('/app/raw_orders/day_*'):
        fname = os.path.basename(fp)
        m = FN_PATTERN.match(fname)
        if not m:
            continue
        day = int(m.group(1))
        store = m.group(2)
        prods = parse_order_file(fp)
        if prods:
            orders[(day, store)] = dict(prods)
    print(f"  {len(orders)} entries")

    print("Loading supplier deliveries...")
    supplier_deliveries = {}
    for fp in glob('/app/raw_supplier_receipts/day_*'):
        fname = os.path.basename(fp)
        m = SUP_PATTERN.match(fname)
        if not m:
            continue
        day = int(m.group(1))
        producer = m.group(2)
        prods = parse_supplier_file(fp)
        if prods:
            supplier_deliveries[(day, producer)] = dict(prods)
    print(f"  {len(supplier_deliveries)} entries")

    print("Loading wholesaler receipts...")
    ws_by_day = defaultdict(list)
    for fp in glob('/app/raw_wholesaler_receipts/day_*.txt'):
        fname = os.path.basename(fp)
        m = SUP_PATTERN.match(fname)
        if not m:
            continue
        day = int(m.group(1))
        producer = m.group(2)
        content = open(fp).read()
        seq_m = re.search(r'DAILY_SEQUENCE_NO:\s*(\d+)', content)
        if seq_m:
            ws_by_day[day].append((int(seq_m.group(1)), producer))
    for day in ws_by_day:
        ws_by_day[day].sort()
    total_ws = sum(len(v) for v in ws_by_day.values())
    print(f"  {total_ws} receipts across {len(ws_by_day)} days")

    print("Loading store receipts...")
    st_by_day = defaultdict(list)
    for fp in glob('/app/raw_wholesaler_store_receipts/day_*.txt'):
        fname = os.path.basename(fp)
        m = FN_PATTERN.match(fname)
        if not m:
            continue
        day = int(m.group(1))
        store = m.group(2)
        content = open(fp).read()
        seq_m = re.search(r'DAILY_SEQUENCE_NO:\s*(\d+)', content)
        units_m = re.search(r'TOTAL_DELIVERED_UNITS:\s*(\d+)', content)
        if seq_m and units_m:
            st_by_day[day].append((int(seq_m.group(1)), store, int(units_m.group(1))))
    for day in st_by_day:
        st_by_day[day].sort()
    total_st = sum(len(v) for v in st_by_day.values())
    print(f"  {total_st} receipts across {len(st_by_day)} days")

    print("Loading sales log...")
    sales_agg = {}
    with open('/app/sales_log.csv') as f:
        reader = csv.DictReader(f)
        for row in reader:
            key = (int(row['Day']), row['Store_ID'], row['Product_ID'])
            d, s, l = sales_agg.get(key, (0, 0, 0))
            sales_agg[key] = (d + int(row['Reported_Demand']),
                              s + int(row['Sold_Quantity']),
                              l + int(row['Lost_Sales']))
    print(f"  {len(sales_agg)} entries")

    # ------------------------------------------------------------
    # SIMULATION
    # ------------------------------------------------------------
    print("Simulating supply chain...")

    wh_inv = defaultdict(list)
    store_inv = defaultdict(lambda: defaultdict(list))
    store_intake = defaultdict(int)

    all_days = set(ws_by_day.keys()) | set(st_by_day.keys())
    all_days = sorted(all_days)
    print(f"  Simulating {len(all_days)} days: {min(all_days)} to {max(all_days)}")

    for day in all_days:
        if day > 365:
            break

        # 1. Accept supplier deliveries
        if day in ws_by_day:
            for seq, producer in ws_by_day[day]:
                key = (day, producer)
                if key in supplier_deliveries:
                    for prod, qty in supplier_deliveries[key].items():
                        wh_inv[prod].append([producer, day, qty])

        # 2. Fulfill store orders
        if day in st_by_day:
            for seq, store, total_units in st_by_day[day]:
                key = (day, store)
                if key not in orders:
                    continue

                store_order = orders[key]
                total_ordered = sum(store_order.values())

                if total_ordered == 0:
                    continue

                # Allocate products to store
                alloc = {}
                for prod, ordered_qty in store_order.items():
                    available = sum(item[2] for item in wh_inv.get(prod, []))
                    if available > 0:
                        alloc[prod] = min(ordered_qty, available)

                total_alloc = sum(alloc.values())
                if total_alloc == 0:
                    continue

                # Scale to match total_units
                if total_alloc > total_units:
                    scale = total_units / total_alloc
                    for prod in list(alloc.keys()):
                        new_qty = int(alloc[prod] * scale)
                        if new_qty > 0:
                            alloc[prod] = new_qty
                        else:
                            del alloc[prod]

                    # Adjust for rounding
                    diff = total_units - sum(alloc.values())
                    if diff > 0 and alloc:
                        for prod in sorted(alloc.keys()):
                            if diff <= 0:
                                break
                            max_avail = sum(item[2] for item in wh_inv.get(prod, []))
                            add = min(diff, max_avail - alloc[prod])
                            if add > 0:
                                alloc[prod] += add
                                diff -= add

                # Execute allocation from wholesaler FIFO
                for prod, alloc_qty in alloc.items():
                    remaining = alloc_qty
                    new_inv = []
                    for item in wh_inv.get(prod, []):
                        if remaining <= 0:
                            new_inv.append(item)
                        else:
                            producer, src_day, avail = item
                            take = min(avail, remaining)
                            if take > 0:
                                ik = (store, prod, producer, src_day)
                                store_intake[ik] += take
                                store_inv[store][prod].append([producer, src_day, take])
                                remaining -= take
                            if avail - take > 0:
                                new_inv.append([producer, src_day, avail - take])
                    wh_inv[prod] = new_inv

    print(f"  Store intake entries: {len(store_intake)}")
    print(f"  Store inventory entries: {sum(len(v) for v in sum(store_inv.values(), defaultdict(list).values()) if False)}")

    # Count non-empty store products
    total_batches = 0
    for store in store_inv:
        for prod in store_inv[store]:
            total_batches += len(store_inv[store][prod])
    print(f"  Total store batches: {total_batches}")

    # ------------------------------------------------------------
    # QUALITY ANALYSIS
    # ------------------------------------------------------------
    print("Determining quality offenders...")

    # Deep copy for consumption
    sim_inv = defaultdict(lambda: defaultdict(list))
    for store in store_inv:
        for prod in store_inv[store]:
            for item in store_inv[store][prod]:
                sim_inv[store][prod].append(item[:])

    confirmed = defaultdict(set)

    for day in range(1, 366):
        for store_idx in range(1, 11):
            store_id = f'S_{store_idx}'
            for prod_idx in range(1, 31):
                prod_id = f'P_{prod_idx}'
                key = (day, store_id, prod_id)

                if key not in sales_agg:
                    continue

                total_demand, total_sold, total_lost = sales_agg[key]
                inv_list = sim_inv.get(store_id, {}).get(prod_id, [])
                total_inv = sum(item[2] for item in inv_list)

                if total_lost > 0 and total_inv > 0 and total_sold < total_demand:
                    # Some consumers couldn't buy despite inventory = quality rejection
                    if inv_list and inv_list[0][2] > 0:
                        producer = inv_list[0][0]
                        confirmed[prod_id].add(producer)

                # Consume inventory
