    for fp in glob('/app/raw_supplier_receipts/day_*'):
        fname = os.path.basename(fp)
        m = SUP_PATTERN.match(fname)
        if not m: continue
        day, prod = int(m.group(1)), m.group(2)
        prods = parse_supplier_file(fp)
        if prods: supplier_deliveries[(day, prod)] = dict(prods)
    print(f"  Supplier deliveries: {len(supplier_deliveries)}")

    ws_by_day = defaultdict(list)
    for fp in glob('/app/raw_wholesaler_receipts/day_*.txt'):
