#!/usr/bin/env python3
"""
Supply Chain Quality Offender Analysis v6

Correct order: consumer sales happen BEFORE the day's store delivery.
"""

import csv
import json
import os
import re
from collections import defaultdict
from glob import glob

FN_PATTERN = re.compile(r'day_(\d+)_(S_\d+)')
SUP_PATTERN = re.compile(r'day_(\d+)_(PR_\d+)')


def parse_order_file(filepath):
    content = open(filepath).read()
    products = []
    if filepath.endswith('.json'):
        import json as j; data = j.loads(content)
        for item in data.get('items', []):
            pid = item.get('prod_id', ''); qty = int(item.get('qty', 0))
            if pid: products.append((pid, qty))
        return products
    if filepath.endswith('.csv'):
        for line in content.strip().split('\n')[1:]:
            parts = line.strip().split(';')
            if len(parts) >= 2: products.append((parts[0].strip(), int(parts[1].strip())))
        return products
    if 'ORDER_PRODUCT' in content:
        for line in content.strip().split('\n'):
            m = re.search(r'ORDER_PRODUCT:\s*(\S+)', line)
            m2 = re.search(r'ORDER_QTY:\s*(\d+)', line)
            if m and m2: products.append((m.group(1), int(m2.group(1))))
        return products
    for line in content.strip().split('\n'):
        m = re.search(r'(\d+)\s+units of product\s+(P_\d+)', line)
        if m: products.append((m.group(2), int(m.group(1))))
    return products


def parse_supplier_file(filepath):
    content = open(filepath).read()
    products = []
    if filepath.endswith('.json'):
        import json as j; data = j.loads(content)
        for item in data.get('items', []):
            pid = item.get('prod_id', ''); qty = int(item.get('delivered_qty', 0))
            if pid: products.append((pid, qty))
        return products
    if filepath.endswith('.csv'):
        for line in content.strip().split('\n')[1:]:
            parts = line.strip().split(';')
            if len(parts) >= 2: products.append((parts[0].strip(), int(parts[1].strip())))
        return products
    if 'PRODUCT' in content and 'DELIVERED_QTY' in content:
        for line in content.strip().split('\n'):
            m = re.search(r'PRODUCT:\s*(\S+)', line)
            m2 = re.search(r'DELIVERED_QTY:\s*(\d+)', line)
            if m and m2: products.append((m.group(1), int(m2.group(1))))
        return products
    for line in content.strip().split('\n'):
        m = re.search(r'delivered\s+(\d+)\s+units of product\s+(P_\d+)', line)
        if m: products.append((m.group(2), int(m.group(1))))
    return products


def main():
    print("Loading data...")

    orders = {}
    for fp in glob('/app/raw_orders/day_*'):
        fname = os.path.basename(fp)
        m = FN_PATTERN.match(fname)
        if not m: continue
        day, store = int(m.group(1)), m.group(2)
        prods = parse_order_file(fp)
        if prods: orders[(day, store)] = dict(prods)
    print(f"  Orders: {len(orders)}")

    supplier_deliveries = {}
    for fp in glob('/app/raw_supplier_receipts/day_*'):
        fname = os.path.basename(fp)
        m = SUP_PATTERN.match(fname)
        if not m: continue
        day, prod = int(m.group(1)), m.group(2)
        prods = parse_supplier_file(fp)
        if prods: supplier_deliveries[(day, prod)] = dict(prods)
    print(f"  Supplier deliveries: {len(supplier_deliveries)}")

    ws_by_day = defaultdict(list)
    for fp in glob('/app/raw_wholesaler_receipts/day_*.txt'):
        fname = os.path.basename(fp)
        m = SUP_PATTERN.match(fname)
        if not m: continue
        day, producer = int(m.group(1)), m.group(2)
        content = open(fp).read()
        sm = re.search(r'DAILY_SEQUENCE_NO:\s*(\d+)', content)
        if sm: ws_by_day[day].append((int(sm.group(1)), producer))
    for day in ws_by_day: ws_by_day[day].sort()
    print(f"  Wholesaler receipts: {sum(len(v) for v in ws_by_day.values())}")

    st_by_day = defaultdict(list)
    for fp in glob('/app/raw_wholesaler_store_receipts/day_*.txt'):
        fname = os.path.basename(fp)
        m = FN_PATTERN.match(fname)
        if not m: continue
        day, store = int(m.group(1)), m.group(2)
        content = open(fp).read()
        sm = re.search(r'DAILY_SEQUENCE_NO:\s*(\d+)', content)
        um = re.search(r'TOTAL_DELIVERED_UNITS:\s*(\d+)', content)
        if sm and um: st_by_day[day].append((int(sm.group(1)), store, int(um.group(1))))
    for day in st_by_day: st_by_day[day].sort()
    print(f"  Store receipts: {sum(len(v) for v in st_by_day.values())}")

    sales_agg = {}
    with open('/app/sales_log.csv') as f:
        reader = csv.DictReader(f)
        for row in reader:
            key = (int(row['Day']), row['Store_ID'], row['Product_ID'])
            d, s, l = sales_agg.get(key, (0, 0, 0))
            sales_agg[key] = (d + int(row['Reported_Demand']),
                              s + int(row['Sold_Quantity']),
                              l + int(row['Lost_Sales']))
    print(f"  Sales: {len(sales_agg)}")

    # ------------------------------------------------------------
    # SIMULATION: Day by day
    # Order within each day:
    # 1. Supplier delivers → wholesaler inventory
    # 2. Consumers buy from store (using carryover inventory)
    # 3. Store receives new delivery (available next day)
    # ------------------------------------------------------------
    print("Simulating supply chain...")

    wh_inv = defaultdict(list)
    store_inv = defaultdict(lambda: defaultdict(list))
    confirmed = defaultdict(set)

    for day in range(1, 366):
        # Step 1: Wholesaler accepts supplier deliveries
        if day in ws_by_day:
            for seq, producer in ws_by_day[day]:
                key = (day, producer)
                if key in supplier_deliveries:
                    for prod, qty in supplier_deliveries[key].items():
                        wh_inv[prod].append([producer, day, qty])

        # Step 2: Process SALES - consumers buy from EXISTING store inventory
        for store_idx in range(1, 11):
            store_id = f'S_{store_idx}'
            for prod_idx in range(1, 31):
                prod_id = f'P_{prod_idx}'
                key = (day, store_id, prod_id)
                if key not in sales_agg:
                    continue

                total_demand, total_sold, total_lost = sales_agg[key]
                inv_at_start = store_inv.get(store_id, {}).get(prod_id, [])
                total_at_start = sum(item[2] for item in inv_at_start)

                # Check for quality rejection:
                # - There were lost sales
                # - There WAS inventory at start that could have been bought
                # - After selling, there's STILL inventory left (consumers refused it)
                if total_lost > 0 and total_at_start > 0:
                    end_inv = total_at_start - total_sold
                    if end_inv > 0 and total_sold < total_demand:
                        # Quality rejection: consumers left inventory on shelf
                        if inv_at_start and inv_at_start[0][2] > 0:
                            confirmed[prod_id].add(inv_at_start[0][0])

                # Consume inventory from sales (FIFO)
                remaining = total_sold
                new_inv = []
                for item in inv_at_start:
                    if remaining <= 0:
                        new_inv.append(item)
                    else:
                        producer, src_day, avail = item
                        take = min(avail, remaining)
                        remaining -= take
                        if avail - take > 0:
                            new_inv.append([producer, src_day, avail - take])
                store_inv[store_id][prod_id] = new_inv

        # Step 3: Fulfill store orders (deliver to stores, available TOMORROW)
        if day in st_by_day:
            for seq, store, total_units in st_by_day[day]:
                key = (day, store)
                if key not in orders:
                    continue

                store_order = orders[key]
                total_ordered = sum(store_order.values())
                if total_ordered == 0:
                    continue

                # Allocate products from wholesaler inventory
                alloc = {}
                for prod, ordered_qty in store_order.items():
                    available = sum(item[2] for item in wh_inv.get(prod, []))
                    if available > 0:
                        alloc[prod] = min(ordered_qty, available)

                total_alloc = sum(alloc.values())
                if total_alloc == 0:
                    continue

                if total_alloc > total_units:
                    scale = total_units / total_alloc
                    for prod in list(alloc.keys()):
                        new_qty = int(alloc[prod] * scale)
                        if new_qty > 0: alloc[prod] = new_qty
                        else: del alloc[prod]
                    diff = total_units - sum(alloc.values())
                    if diff > 0 and alloc:
                        for prod in sorted(alloc.keys()):
                            if diff <= 0: break
                            max_avail = sum(item[2] for item in wh_inv.get(prod, []))
                            add = min(diff, max_avail - alloc[prod])
                            if add > 0: alloc[prod] += add; diff -= add

                for prod, alloc_qty in alloc.items():
                    remaining = alloc_qty
                    new_inv = []
                    for item in wh_inv.get(prod, []):
                        if remaining <= 0:
                            new_inv.append(item)
                        else:
                            producer, src_day, avail = item
                            take = min(avail, remaining)
                            if take > 0:
                                store_inv[store][prod].append([producer, src_day, take])
                                remaining -= take
                            if avail - take > 0:
                                new_inv.append([producer, src_day, avail - take])
                    wh_inv[prod] = new_inv

    total_confirmed = sum(len(v) for v in confirmed.values())
    print(f"\nTotal confirmed: {total_confirmed}")

    result = {}
    for i in range(1, 31):
        p = f'P_{i}'
        if p in confirmed and confirmed[p]:
            result[p] = sorted(confirmed[p], key=lambda x: int(x.split('_')[1]))
        else:
            result[p] = []

    for p, producers in result.items():
        print(f"  {p}: {producers}")

    with open('/app/answer.json', 'w') as f:
        json.dump(result, f, indent=2)
    print("\nWritten to /app/answer.json")


if __name__ == '__main__':
    main()

