#!/usr/bin/env python3
"""
Supply Chain Quality Offender Analysis v7

Key insight: track individual consumer demand trajectories across days.
The 14-day recovery pattern (20%, 50%, 80%, 100%) appears as demand drops.
The day BEFORE a drop is when the consumer received the bad batch.
Cross-reference with supply chain simulation to find the offending producer.
"""

import csv
import json
import os
import re
from collections import defaultdict
from glob import glob

FN_PATTERN = re.compile(r'day_(\d+)_(S_\d+)')
SUP_PATTERN = re.compile(r'day_(\d+)_(PR_\d+)')


def parse_order_file(filepath):
    content = open(filepath).read()
    products = []
    if filepath.endswith('.json'):
        import json as j; data = j.loads(content)
        for item in data.get('items', []):
            pid = item.get('prod_id', ''); qty = int(item.get('qty', 0))
            if pid: products.append((pid, qty))
        return products
    if filepath.endswith('.csv'):
        for line in content.strip().split('\n')[1:]:
            parts = line.strip().split(';')
            if len(parts) >= 2: products.append((parts[0].strip(), int(parts[1].strip())))
        return products
    if 'ORDER_PRODUCT' in content:
        for line in content.strip().split('\n'):
            m = re.search(r'ORDER_PRODUCT:\s*(\S+)', line)
            m2 = re.search(r'ORDER_QTY:\s*(\d+)', line)
            if m and m2: products.append((m.group(1), int(m2.group(1))))
        return products
    for line in content.strip().split('\n'):
        m = re.search(r'(\d+)\s+units of product\s+(P_\d+)', line)
        if m: products.append((m.group(2), int(m.group(1))))
    return products


def parse_supplier_file(filepath):
    content = open(filepath).read()
    products = []
    if filepath.endswith('.json'):
        import json as j; data = j.loads(content)
        for item in data.get('items', []):
            pid = item.get('prod_id', ''); qty = int(item.get('delivered_qty', 0))
            if pid: products.append((pid, qty))
        return products
    if filepath.endswith('.csv'):
        for line in content.strip().split('\n')[1:]:
            parts = line.strip().split(';')
            if len(parts) >= 2: products.append((parts[0].strip(), int(parts[1].strip())))
        return products
    if 'PRODUCT' in content and 'DELIVERED_QTY' in content:
        for line in content.strip().split('\n'):
            m = re.search(r'PRODUCT:\s*(\S+)', line)
            m2 = re.search(r'DELIVERED_QTY:\s*(\d+)', line)
            if m and m2: products.append((m.group(1), int(m2.group(1))))
        return products
    for line in content.strip().split('\n'):
        m = re.search(r'delivered\s+(\d+)\s+units of product\s+(P_\d+)', line)
        if m: products.append((m.group(2), int(m.group(1))))
    return products


def main():
    print("Loading data...")

    # Orders
    orders = {}
    for fp in glob('/app/raw_orders/day_*'):
        fname = os.path.basename(fp)
        m = FN_PATTERN.match(fname)
        if not m: continue
        day, store = int(m.group(1)), m.group(2)
        prods = parse_order_file(fp)
        if prods: orders[(day, store)] = dict(prods)
    print(f"  Orders: {len(orders)}")

    # Supplier deliveries
    supplier_deliveries = {}
    for fp in glob('/app/raw_supplier_receipts/day_*'):
        fname = os.path.basename(fp)
        m = SUP_PATTERN.match(fname)
        if not m: continue
        day, prod = int(m.group(1)), m.group(2)
        prods = parse_supplier_file(fp)
        if prods: supplier_deliveries[(day, prod)] = dict(prods)
    print(f"  Supplier deliveries: {len(supplier_deliveries)}")

    # Wholesaler receipts
    ws_by_day = defaultdict(list)
    for fp in glob('/app/raw_wholesaler_receipts/day_*.txt'):
        fname = os.path.basename(fp)
        m = SUP_PATTERN.match(fname)
        if not m: continue
        day, producer = int(m.group(1)), m.group(2)
        content = open(fp).read()
        sm = re.search(r'DAILY_SEQUENCE_NO:\s*(\d+)', content)
        if sm: ws_by_day[day].append((int(sm.group(1)), producer))
    for day in ws_by_day: ws_by_day[day].sort()
    print(f"  Wholesaler receipts: {sum(len(v) for v in ws_by_day.values())}")

    # Store receipts
    st_by_day = defaultdict(list)
    for fp in glob('/app/raw_wholesaler_store_receipts/day_*.txt'):
        fname = os.path.basename(fp)
        m = FN_PATTERN.match(fname)
        if not m: continue
        day, store = int(m.group(1)), m.group(2)
        content = open(fp).read()
        sm = re.search(r'DAILY_SEQUENCE_NO:\s*(\d+)', content)
        um = re.search(r'TOTAL_DELIVERED_UNITS:\s*(\d+)', content)
        if sm and um: st_by_day[day].append((int(sm.group(1)), store, int(um.group(1))))
    for day in st_by_day: st_by_day[day].sort()
    print(f"  Store receipts: {sum(len(v) for v in st_by_day.values())}")

    # Sales log - group by (day, store, product), preserving row order
    print("Loading sales log...")
    sales_groups = defaultdict(list)
    with open('/app/sales_log.csv') as f:
        reader = csv.DictReader(f)
        for row in reader:
            key = (int(row['Day']), row['Store_ID'], row['Product_ID'])
            sales_groups[key].append({
                'demand': int(row['Reported_Demand']),
                'sold': int(row['Sold_Quantity']),
                'lost': int(row['Lost_Sales'])
            })

    # Build consumer trajectories
    # consumer_trajs[(store, product, consumer_index)] = {day: (demand, sold, lost)}
    consumer_trajs = defaultdict(dict)
    for (day, store, prod), rows in sales_groups.items():
        for idx, r in enumerate(rows, 1):
            consumer_trajs[(store, prod, idx)][day] = (r['demand'], r['sold'], r['lost'])
    print(f"  Consumer trajectories: {len(consumer_trajs)}")

    # ------------------------------------------------------------
    # DETECT QUALITY RECOVERY PATTERNS
    # Search for the 14-day recovery pattern in each consumer's demand
    # Pattern: baseline drops to ~20% (3 days), ~50% (4 days), ~80% (7 days)
    # Then returns to baseline
    # ------------------------------------------------------------
    print("Detecting quality recovery patterns...")

    quality_events = defaultdict(list)  # product -> [(trigger_day, store, consumer_idx)]

    for (store, prod, cidx), traj in consumer_trajs.items():
        sorted_days = sorted(traj.keys())
        demands = [traj[d][0] for d in sorted_days]

        # Find recovery patterns: a sudden drop followed by gradual recovery
        for i in range(len(sorted_days) - 1):
            trigger_day = sorted_days[i]
            next_day = sorted_days[i + 1]

            curr_demand = traj[trigger_day][0]
            next_demand = traj[next_day][0]
            curr_sold = traj[trigger_day][1]

